package org.apache.commons.csv;
import static org.apache.commons.csv.Constants.BACKSLASH;
import static org.apache.commons.csv.Constants.COMMA;
import static org.apache.commons.csv.Constants.CR;
import static org.apache.commons.csv.Constants.CRLF;
import static org.apache.commons.csv.Constants.DOUBLE_QUOTE_CHAR;
import static org.apache.commons.csv.Constants.LF;
import static org.apache.commons.csv.Constants.TAB;
import java.io.IOException;
import java.io.Reader;
import java.io.Serializable;
import java.io.StringWriter;
import java.util.Arrays;
import java.util.HashSet;
import java.util.Set;
import static org.junit.jupiter.api.Assertions.*;
import org.apache.commons.csv.CSVFormat;
import org.junit.jupiter.api.Test;

import java.lang.reflect.Field;

public class CSVFormatTest {

    @Test
    public void testIsEscapeCharacterSet_whenEscapeCharacterIsNull() throws Exception {
        CSVFormat csvFormat = CSVFormat.DEFAULT;

        // Use reflection to set escapeCharacter to null
        Field escapeField = CSVFormat.class.getDeclaredField("escapeCharacter");
        escapeField.setAccessible(true);
        escapeField.set(csvFormat, null);

        assertFalse(csvFormat.isEscapeCharacterSet());
    }

    @Test
    public void testIsEscapeCharacterSet_whenEscapeCharacterIsSet() throws Exception {
        CSVFormat csvFormat = CSVFormat.DEFAULT;

        // Use reflection to set escapeCharacter to a non-null Character
        Field escapeField = CSVFormat.class.getDeclaredField("escapeCharacter");
        escapeField.setAccessible(true);
        escapeField.set(csvFormat, '\\');

        assertTrue(csvFormat.isEscapeCharacterSet());
    }
}
